"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[477],{10:n=>{n.exports=JSON.parse('{"blogPosts":[{"id":"/parallel101/notebook","metadata":{"permalink":"/blog/parallel101/notebook","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/parallel101/notebook.md","source":"@site/blog/parallel101/notebook.md","title":"Parallel101","description":"CH1","date":"2023-02-15T12:12:11.000Z","formattedDate":"February 15, 2023","tags":[{"label":"c++","permalink":"/blog/tags/c"},{"label":"HPC","permalink":"/blog/tags/hpc"}],"readingTime":2.945,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"Parallel101","tags":["c++","HPC"]},"nextItem":{"title":"c++\u9762\u5411\u5bf9\u8c61","permalink":"/blog/c++\u9762\u5411\u5bf9\u8c61"}},"content":"\x3c!--truncate--\x3e\\n\\n## CH1\\n\\n### \u7f16\u8bd1\u5668\\n\\n```bash\\ng++ main.cpp -o a.out\\n\\n# less \u53ef\u4ee5\u8ba9\u6253\u5370\u7684\u53cd\u6c47\u7f16\u4e0a\u4e0b\u6eda\u52a8\\nobjdump -D a.out | less\\n\\n\\n```\\n\\n### \u591a\u6587\u4ef6\u7f16\u8bd1\u548c\u94fe\u63a5\\n\\n#### \u5148\u628a\u6bcf\u4e2a\u6587\u4ef6\u7f16\u8bd1\u6210\u4e34\u65f6\u5bf9\u8c61\u6587\u4ef6\\n\\n\\n> g++ -c hello.cpp -o hello.o\\n> g++ -c main.cpp -o main.o\\n> g++ hello.o main.o -o a.out\\n\\n```bash\\n# hello.cpp main.cpp\\n\\n# solution1 & problem: After change one file, all files should be re compiled\\n\\ng++ hello.cpp main.cpp -o a.out \\n\\n# solution2 \\"-c\\"\u751f\u6210\u4e34\u65f6\u7684\u5bf9\u8c61\u6587\u4ef6\\ng++ -c hello.cpp -o hello.o\\ng++ -c main.cpp -o main.o\\ng++ hello.o main.o -o a.out\\n\\n```\\n\\n#### Make\u5230Cmake\\n\\nGNU\u53d1\u660e\u4e86make\\n\\n![](assets/image-20230122220451044.png)\\n\\n\\n\\n| Make                       | Cmake                                            |\\n| -------------------------- | ------------------------------------------------ |\\n| Unix\u901a\u7528\uff0cWindows\u4e0d\u901a\u7528    | CMakeList.txt ==>\u5f53\u524d\u7cfb\u7edf\u652f\u6301\u7684                  |\\n| \u51c6\u786e\u6307\u660e\u6bcf\u4e2a\u9879\u76ee\u4e4b\u95f4\u7684\u4f9d\u8d56 | \u81ea\u52a8\u68c0\u6d4b\u6e90\u6587\u4ef6\u548c\u5934\u6587\u4ef6\u4e4b\u95f4\u7684\u5173\u7cfb\uff0c\u5bfc\u51fa\u5230Makefile |\\n| \u8bed\u6cd5\u7b80\u5355                   | CMake\u5177\u6709\u9ad8\u7ea7\u8bed\u6cd5,\u53ef\u4ee5make install               |\\n| \u4e0d\u540c\u7684\u7f16\u8bd1\u5668\u6709\u4e0d\u540c\u7684\u53c2\u6570   | \u81ea\u52a8\u68c0\u6d4b\u7f16\u8bd1\u5668\uff0c\u6dfb\u52a0flag                         |\\n\\n\\n\\nCmakeLists.txt\\n\\n```cmake\\nproject(hellocmake)\\n\\nadd_executable(a.out main.cpp hello.cpp)                                          \\n```\\n\\n>  cmake -B build\\n\\n \u6784\u5efa\u6587\u4ef6\u5230build\u76ee\u5f55\\n\\n![](assets/image-20230122224320663.png)\\n\\n \u6267\u884c\\n\\n> make\\n>\\n> ./a.out\\n\\n#### Library(\u5e93)\\n\\n* \u628a\u5171\u7528\u7684\u529f\u80fd\u505a\u6210\u4e00\u4e2a\u5e93\uff0c\u53ef\u4ee5\u88ab\u53ef\u6267\u884c\u6587\u4ef6\u6216\u5176\u4ed6\u5e93\u8c03\u7528\\n\\n* \u5206\u4e3a **\u9759\u6001\u5e93** \u548c**\u52a8\u6001\u5e93**\\n\\n  ![](assets/image-20230122225419586.png)\\n\\n  ![](assets/image-20230122225516830.png)\\n\\n \\n\\n#### Cmake\u4e2d\u7684\u9759\u6001\u5e93\u548c\u52a8\u6001\u5e93\\n\\n\u67e5\u770b\u52a8\u6001\u94fe\u63a5\u5185\u5bb9\\n\\n```bash\\n# Linux\\nldd a.out\\n\\n# MacOS\\notool -L a.out\\n```\\n\\n![](assets/image-20230122231354334.png)\\n\\n\\n\\n\u4fee\u6539CMakeLists.txt\\n\\n```cmake\\nproject(hellocmake)\\n\\nadd_library(hellolib STATIC hello.cpp)\\nadd_executable(a.out main.cpp hello.cpp)\\ntarget_link_libraries(a.out PUBLIC hellolib)\\n```\\n\\n> STATIC \u8868\u793a\u9759\u6001\u94fe\u63a5\u5e93\\n\\n\u4fee\u6539\u540ebuild\u91cc\u589e\u52a0\u4e86 libhellolib.a\\n\\n![](assets/image-20230122231815862.png)\\n\\n\u7136\u800c\u67e5\u770b\u94fe\u63a5\u5185\u5bb9\u5e76\u6ca1\u6709\u65b0\u589e\\n\\n![](assets/image-20230122231354334.png)\\n\\n\\n\\n\u4fee\u6539CMakeLists.txt\\n\\n```cmake\\nproject(hellocmake)\\n\\nadd_library(hellolib SHARED hello.cpp)\\nadd_executable(a.out main.cpp hello.cpp)\\ntarget_link_libraries(a.out PUBLIC hellolib)\\n```\\n\\n> SHARED \u8868\u793a\u52a8\u6001\u94fe\u63a5\u5e93\\n\\n*.dylib\u81ea\u52a8\u653e\u5728rpath\u8def\u5f84\u4e0b\uff0cmake\u65f6\u94fe\u63a5\\n\\n![](assets/image-20230122232732689.png)\\n\\n\\n\\n* \u9759\u6001\u5e93\uff08.a\uff09\u88ab\u5220\u9664\u540e\u4ecd\u53ef\u4ee5\u8fd0\u884c\\n* \u52a8\u6001\u5e93\uff08.so/.dylib\uff09\u88ab\u5220\u9664\u540e\u8fd0\u884c\u4f1a\u62a5\u9519 \\n\\n#### \u5173\u4e8e\u5934\u6587\u4ef6\\n\\n\u91c7\u7528#include\u9884\u5b9a\u4e49\uff0c\u662f\u4e00\u79cd\u76f4\u63a5\u7684\u66ff\u6362\\n\\n* `<xxx.h>` \u8868\u793a\u4e0d\u8981\u5728\u5f53\u524d\u76ee\u5f55\u4e0b\u641c\u7d22\\n* `\\"xxx.h\\" `\u8868\u793a\u4f18\u5148\u641c\u7d22\u5f53\u524d\u76ee\u5f55\uff0c\u518d\u641c\u7d22\u7cfb\u7edf\u76ee\u5f55\\n\\n**Problem\uff1a \u591a\u6587\u4ef6\u9012\u5f52\u5730\u5f15\u7528\u540c\u4e00\u4e2a\u5934\u6587\u4ef6**\\n\\n![](assets/image-20230122234948899.png)\\n\\n**Solution**\\n\\n* #pragma once\\n* #ifndef...\\n\\n\\n\\n### Cmake\u5b50\u6a21\u5757\\n\\n![](assets/image-20230122235653250.png)\\n\\n\u540c\u6837\u7684\u662f\u4e00\u79cd\u9884\u5b9a\u4e49\u66ff\u6362\u7684\u65b9\u5f0f\\n\\n\u56e0\u4e3a\u79fb\u52a8\u5230\u4e86hellolib\u6587\u4ef6\u5939\u4e0b\uff0c\u6240\u4ee5main.cpp\u8981\u505a\u4e00\u5b9a\u4fee\u6539\\n\\n```\\n#include \\"hellolib/hello.h\\"\\n```\\n\\n\u907f\u514d\u4fee\u6539\u7684\u65b9\u5f0f\u4e3a\\n\\nCMakeLists.txt\u4e2d\u6dfb\u52a0\\n\\n```\\ntarget_include_directories(a.out PUBLIC hellolib)\\n```\\n\\n\\n\\n\\n\\n==Cmake\u66f4\u591a\u5185\u5bb9\u65b0\u5f00\u4e00p\u6765\u5199\u3002=="},{"id":"/c++\u9762\u5411\u5bf9\u8c61","metadata":{"permalink":"/blog/c++\u9762\u5411\u5bf9\u8c61","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/c++\u9762\u5411\u5bf9\u8c61/index.md","source":"@site/blog/c++\u9762\u5411\u5bf9\u8c61/index.md","title":"c++\u9762\u5411\u5bf9\u8c61","description":"\u5934\u6587\u4ef6\u3001\u7c7b","date":"2023-02-15T12:12:11.000Z","formattedDate":"February 15, 2023","tags":[{"label":"c++","permalink":"/blog/tags/c"}],"readingTime":6.175,"hasTruncateMarker":true,"authors":[],"frontMatter":{"title":"c++\u9762\u5411\u5bf9\u8c61","tags":["c++"]},"prevItem":{"title":"Parallel101","permalink":"/blog/parallel101/notebook"}},"content":"\x3c!--truncate--\x3e\\n\\n## \u5934\u6587\u4ef6\u3001\u7c7b\\n\\nguard\uff08\u9632\u536b\u5f0f\u58f0\u660e\uff09\\n\\n\u53ea\u6709\u7b2c\u4e00\u6b21include\u4f1ainclude\u8fdb\u6765\uff0c\u7b2c\u4e8c\u6b21\u4e0d\u4f1a\u88abinclude\u8fdb\u6765\\n\\n```\\n#ifndef __Complex__\\n#define __Complex__\\n...\\n\\n\\n#endif\\n```\\n\\n\u5b9a\u4e49\u4e00\u4e2a\u590d\u6570\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n   ...\\n  private:\\n  double re,im;\\n}\\n\\ncomplex c1(0,0.5)\\n```\\n\\n\u7f3a\u70b9\uff1a\u5982\u679c\u60f3\u628adouble\u6539\u4e3afloat\u5c31\u5f97\u91cd\u65b0\u5b9a\u4e49\u4e00\u4e2a\u7c7b\\n\\n===> template(\u6a21\u7248)\\n\\n```cpp\\ntemplate<typename T>\\nclass complex{\\n  public:\\n  complex(T r = 0,T i = 0): re(r)\\t,im(i){}\\n   ...\\n  private:\\n  T re,im;\\n}\\n\\ncomplex<double> c1(0,0.5)\\ncomplex<float> c1(0,0.5)\\n```\\n\\n\\n\\n**Inline(\u5185\u8054)**\\n\\n\u7a0b\u5e8f\u5458\u8bbe\u8ba1\u662f\u5426inline\u53ea\u662f\u7ed9\u7f16\u8bd1\u5668\u5efa\u8bae\uff0c\u7f16\u8bd1\u5668\u6700\u7ec8\u662f\u5426inline\u53d6\u51b3\u4e8e\u51fd\u6570\u662f\u5426\u590d\u6742\u3002\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n  \\n  // \u5728class\u672c\u4f53\u91cc\u76f4\u63a5\u5b9a\u4e49\u7684\u51fd\u6570\u4f1a\u81ea\u52a8inline\\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n}\\n\\n// class\u672c\u4f53\u5185\u58f0\u660e\u4e86\u7684\uff0c\u800c\u672c\u4f53\u5916\u60f3\u8981\u5efa\u8bae\u7f16\u8bd1\u5668inline\u9700\u8981\u52a0inline\u5173\u952e\u8bcd\\ninline double img(const complex& x){\\n  return x.img();\\n}\\n\\nvoid real(double r){real = r;}\\n```\\n\\n\\n\\n**\u6784\u9020\u51fd\u6570**\\n\\n```cpp\\nclass complex{\\n  public:\\n  // \uff081\uff09\u6700\u597d\u5199\u6210\u8fd9\u6837\uff0c\u76f4\u63a5\u521d\u59cb\u5316 r\u548ci\\n  complex(double r = 0,double i = 0): // =0\u4e3a\u9ed8\u8ba4\u53c2\u6570\\n  re(r)\\t,im(i) // \u521d\u59cb\u5217\\n  {}   // \u8d4b\u503c\\n  // \uff082\uff09\u800c\u6700\u597d\u4e0d\u8981\u5199\u6210\u8fd9\u6837\uff0c\u5148\u521d\u59cb\u5316\uff0c \u518d\u8d4b\u503cr\u548ci\\n  complex(double r = 0,double i = 0) {re = r; im = i};\\n  \\n  // \u5728class\u672c\u4f53\u91cc\u76f4\u63a5\u5b9a\u4e49\u7684\u51fd\u6570\u4f1a\u81ea\u52a8inline\\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n}\\n\\n{\\n  complex c1(1,2);  //1+2i\\n  complex c1;  // 0 + 0i\\n  complex *p = new complex(4);\\n}\\n```\\n\\n\u53ef\u4ee5\u628a\u6784\u9020\u51fd\u6570\u653e\u5728private\uff0c\u8868\u793a\u8be5\u7c7b\u5bf9\u8c61\u4e0d\u80fd\u88ab\u5176\u4ed6\u7c7b\u521b\u5efa\uff0c\u4f46\u662f\u53ef\u4ee5\u4f7f\u7528\u53cb\u5143\u6765\u521b\u5efa\u3002\\n\\n\u5e94\u7528\uff1asingleton(\u5355\u4f8b)\u8bbe\u8ba1\u6a21\u5f0f\\n\\n```cpp\\nclass A{\\npublic:\\n  static A& getInstance();\\n  setup(){...};\\nprivate:\\n  A();\\n  A(const A& rhs);\\n  ...\\n}\\n\\nA& A::getInstance(){\\n  static A a;\\n  return a;\\n}\\n\\nA::getInstance().setup();\\n```\\n\\n\\n\\n**Overload(\u91cd\u8f7d)**\\n\\n\u540c\u540d\u51fd\u6570\uff0c\u4e0d\u540c\u53c2\u6570\u5217\u8868\u6216\u8fd4\u56de\u503c\u3002\\n\\n\u80fd\u91cd\u8f7d\u7684\u539f\u56e0\u662f\uff0c\u7f16\u8bd1\u540e\u4e0d\u540c\u53c2\u6570\u8fd4\u56de\u503c\u7684\u540c\u540d\u51fd\u6570\u5728\u7f16\u8bd1\u5668\u770b\u6765\u540d\u5b57\u5e76\u4e0d\u4e00\u6837\\n\\n![image-20230215162624548](assets/image-20230215162624548.png)\\n\\n\\n\\n```cpp\\nclass complex{\\n  public:\\n  // 1\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n  // 2\\n  complex():re(0),im(0){}\\n  // 1\u30012\u4e0d\u80fd\u540c\u65f6\u51fa\u73b0\uff0c\u56e0\u4e3a1\u6709\u9ed8\u8ba4\u503c\\n  \\n  // 3\\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n}\\n\\n// 4\\nvoid real(double r){real = r;}\\n// 3\u30014\u53ef\u4ee5\u540c\u65f6\u51fa\u73b0\\n```\\n\\n\\n\\n==const member function \uff08\u5e38\u91cf\u6210\u5458\u51fd\u6570\uff09==\\n\\n```cpp\\ndouble real() const{\\n\\treturn re;\\n}\\n```\\n\\n\\n\\n* const\u7528\u5728\u6210\u5458\u51fd\u6570\u8868\u793a\u201c\u4e0d\u4f1a\u6539\u53d8\u7c7b\u5bf9\u8c61\u6570\u636e\u5185\u5bb9\u7684\u6210\u5458\u51fd\u6570\u201d\\n* const int/double/complex \u8868\u793a\u5e38\u91cf\uff0c\u4e0d\u4f1a\u53d1\u751f\u53d8\u5316\u7684\u91cf\\n\\n\u4e0b\u9762\u8fd9\u79cd\u60c5\u51b5\uff0cconst member function\u7684const\u4e0d\u53ef\u7701\u7565\uff0c\u5426\u5219\u7f16\u8bd1\u4e0d\u901a\u8fc7.\\n\\n```cpp\\ndouble real() const{\\n\\treturn re;\\n}\\n\\n{\\n  const complex c(2,1);\\n  cout << c1.real();\\n}\\n```\\n\\n* \u7c7b\u4e2d\u67d0\u4e2a\u51fd\u6570\u52a0\u4e86const\uff0c\u8fd9\u65f6\u5019\u5176\u4ed6\u4eba\u5b9a\u4e49\u7684\u65e0\u8bba\u662fconst\u7684\u5bf9\u8c61\u8fd8\u662f\u975econst\u7684\u5bf9\u8c61\uff0c\u90fd\u53ef\u4ee5\u8c03\u7528\u8fd9\u4e2a\u51fd\u6570\\n* \u4f46\u67d0\u4e2a\u51fd\u6570\u6ca1\u6709\u52a0const\uff08\u5373\u6210\u5458\u53d8\u91cf\u53ef\u4ee5\u88ab\u4fee\u6539\uff09\uff0c\u8fd9\u65f6\u5019\u5176\u4ed6\u4eba\u5b9a\u4e49\u4e86\u4e00\u4e2aconst\u7684\u5bf9\u8c61\uff0c\u5c31\u65e0\u6cd5\u518d\u8c03\u7528\u8fd9\u4e2a\u53ef\u4ee5\u4fee\u6539\u6210\u5458\u53d8\u91cf\u7684\u51fd\u6570\u4e86\u3002\\n\\n\u56e0\u6b64\u7c7b\u8bbe\u8ba1\u8005\u8981\u5e94const\u5c3dconst\u3002\\n\\n\\n\\n\\n\\n## \u53c2\u6570\u4f20\u9012/\u8fd4\u56de\u503c\u4f20\u9012\\n\\n* pass by Value\\n* pass by Reference\\n* pass by Reference Const\\n\\n\u5c3d\u91cf\u4e0d\u8981pass by Value\\n\\n\u5f15\u7528\u5728\u5e95\u5c42\u5176\u5b9e\u5c31\u662f\u6307\u9488\\n\\nReference Const\u5c31\u662f\u4f20\u9012\u5f15\u7528\uff0c\u4f46\u662f\u51fd\u6570\u4e0d\u80fd\u5bf9\u8fd9\u4e2a\u5f15\u7528\u8fdb\u884c\u4fee\u6539\uff0c\u5426\u5219\u7f16\u8bd1\u4f1a\u51fa\u9519\\n\\n\\n\\n\\n\\n* return  by Value\\n* return by Reference\\n* return by Reference Const\\n\\n\u5982\u679c\u53ef\u4ee5\u7684\u8bdd\u5c3d\u91cf\u8fd4\u56dereference\uff0c\u4e3a\u4e86\u66f4\u5feb\u3002\\n\\n\u4e0d\u80fd\u8fd4\u56dereference\u7684\u60c5\u51b5\uff1a\u9700\u8981\u8fd4\u56de\u4e00\u4e2a\u65b0\u521b\u5efa\u7684\u5bf9\u8c61\uff0c\u800c\u4e0d\u80fd\u7528\u5df2\u6709\u7684\u4ee3\u66ff\uff0c\u56e0\u4e3a\u5728\u51fd\u6570\u7ed3\u675f\u65f6\uff0c\u65b0\u521b\u5efa\u7684\u5bf9\u8c61\u4e5f\u6ca1\u4e86\uff01\\n\\n## friend\u53cb\u5143\\n\\n\u58f0\u660e\u4e00\u4e2afriend\u51fd\u6570\uff0c\u53ef\u4ee5\u4e0d\u7ecf\u8fc7public\u65b9\u6cd5\uff0c\u76f4\u63a5\u83b7\u5f97\u7c7b\u5bf9\u8c61\u7684private\u6570\u636e\u3002\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\xb7\\n  \\n  double real() const\\t{return re;} // inline function\\n  double img() const;// declaration\\n  private:\\n  double re,im;\\n  \\n  // \u58f0\u660e\u53cb\u5143\\n  friend complex& __doapl(complex*, const complex&);\\n}\\n\\ninline complex& __doapl(complex* ths,const complex& r){\\n  ths->re += r.re;\\n  ths->im += r.im;\\n  return *ths;\\n}\\n\\n\\n```\\n\\n\\n\\n**\u76f8\u540cclass\u7684\u5404\u4e2aObjects\u4e92\u4e3a\u53cb\u5143**\\n\\n```cpp\\nclass complex{\\n  public:\\n  complex(double r = 0,double i = 0): re(r)\\t,im(i){}\\n  \\n int func(const complex& param){\\n   return param.re;\\n }\\n  private:\\n  double re,im;\\n}\\n\\n{\\n  complex c1(2,1);\\n  commplex c2;\\n  c2.func(c1);\\n}\\n```\\n\\n\\n\\n## \u64cd\u4f5c\u7b26\u91cd\u8f7d\\n\\nc++\u91cc\u64cd\u4f5c\u7b26\u4e5f\u662f\u4e00\u79cd\u51fd\u6570\uff0c\u53ef\u4ee5\u91cd\u65b0\u5b9a\u4e49\u7684\\n\\n```cpp\\ninline complex& __doapl(complex *ths, const complex &r){\\n  ths->re += r.re;\\n  ths->im += r.im;\\n  return *ths;\\n}\\n\\n// 1\\ninline complex& += (const complex &r){\\n  return __doapl(this, r);\\n}\\n\\n// 2  \u662f\u9519\u7684 this\u4e0d\u80fd\u5199\u51fa\u6765 \u4ed6\u662f\u88ab\u7f16\u8bd1\u5668\u5904\u7406\u4e4b\u540e\u7684\u7ed3\u679c\uff08\u4e0b\u56fe\u662f\u793a\u610f\u56fe\uff09\\n//    \u7f16\u8bd1\u5668\u5904\u7406\u540e\u7684this\u53ef\u80fd\u662f\u7b2c\u4e00\u4e2a\u53c2\u6570\uff0c\u4e5f\u53ef\u80fd\u662f\u6700\u540e\u4e00\u4e2a\u53c2\u6570\uff0c\u53d6\u51b3\u4e8e\u4e0d\u540c\u7684\u7f16\u8bd1\u5668\\ninline complex& += (this, const complex &r){\\n  return __doapl(this, r);\\n}\\n\\n\\n```\\n\\n>  \u7f16\u8bd1\u5668\u770b\u5f85\u201cc2 += c1\u201d\\n>\\n>  += (c2, c1)\\n>\\n>  +=\u662f\u4e00\u4e2a\u51fd\u6570\\n\\n\\n\\n![image-20230215162547923](assets/image-20230215162547923.png)\\n\\n**this**\\n\\n\u6240\u6709\u7684\u6210\u5458\u51fd\u6570\u90fd\u542b\u6709\u4e00\u4e2a\u9690\u85cf\u7684\u53c2\u6570\uff1a this\uff0c \u53ef\u4ee5\u628a\u5b83\u5199\u51fa\u6765\u3002\\n\\n\u8c01\u8c03\u7528\u8fd9\u4e2a\u51fd\u6570\uff0c\u8c01\u5c31\u662f\u90a3\u4e2athis\u3002\\n\\nthis\u662f\u4e2a\u6307\u9488\uff0c\u6307\u5411\u8c03\u7528\u51fd\u6570\u7684\u5bf9\u8c61"}]}')}}]);